;; --- shared_logic: costs (generated from compile_logic) ---

(defn is-over-budget
  "Check if total cost exceeds budget. Budget of 0 means unlimited."
  [state budget]
  (if (<= budget 0)
      false
      (>= (:total-cost state) budget)
  )
)

(defn budget-remaining
  "Return remaining budget in USD. Budget of 0 means unlimited (returns -1)."
  [state budget]
  (if (<= budget 0)
      -1.0
      (max 0.0 (- budget (:total-cost state)))
  )
)

(defn reset
  "Reset all cost tracking state."
  [state]
  (-> state
      (assoc :records [])
      (assoc :total-input-tokens 0)
      (assoc :total-output-tokens 0)
      (assoc :total-cost 0.0))
)

(defn cost-compute
  "Compute cost from token count and price per 1M tokens."
  [tokens price-per-million]
  (/ (* (double tokens) price-per-million) 1.0e+06)
)

(defn record-usage
  "Record a usage entry and update running totals."
  [state input-tokens output-tokens model]
  (-> state
      (update :total-input-tokens + input-tokens)
      (update :total-output-tokens + output-tokens))
)

(defn total-tokens
  "Return total token count (input + output)."
  [state]
  (+ (:total-input-tokens state) (:total-output-tokens state))
)

(defn get-summary
  "Format a one-line cost summary showing totals."
  [state]
  (format "$%s (%s input, %s output)" (:total-cost state) (:total-input-tokens state) (:total-output-tokens state))
)

(defn set-pricing
  "Set the per-token pricing for input and output."
  [state input-price output-price]
  (-> state
      (assoc :input-price input-price)
      (assoc :output-price output-price))
)

(defn cost-per-token
  "Compute the average cost per token. Returns 0.0 if no tokens used."
  [state]
  (let [total (+ (:total-input-tokens state) (:total-output-tokens state))]
  (if (<= total 0)
      0.0
      (/ (:total-cost state) (double total))
  ))
)

(defn has-records
  "Check if any usage records have been logged."
  [state]
  (not (zero? (count (:records state))))
)

(defn total-tokens
  "Return total token count (input + output)."
  [state]
  (+ (:total-input-tokens state) (:total-output-tokens state))
)

(defn cost-summary-short
  "Return a short cost summary string (e.g. $0.05)."
  [state]
  (format "$%s" (:total-cost state))
)

(defn is-free-model
  "Check if the current model has zero cost (total_cost == 0 after usage)."
  [state]
  (zero? (:total-cost state))
)

(defn input-output-ratio
  "Compute ratio of input to output tokens. Returns 0.0 if no output tokens."
  [state]
  (if (zero? (:total-output-tokens state))
      0.0
      (/ (double (:total-input-tokens state)) (double (:total-output-tokens state)))
  )
)

(defn average-cost-per-message
  "Calculate average cost per message. Returns 0.0 if no messages recorded."
  [state]
  (if (zero? (:message-count state))
      0.0
      (/ (double (:total-cost state)) (double (:message-count state)))
  )
)

(defn is-tracking
  "Check if cost tracking is active (has recorded any usage)."
  [state]
  (> (:message-count state) 0)
)

(defn cost-per-input-token
  "Calculate average cost per input token. Returns 0.0 if no input tokens recorded."
  [state]
  (if (zero? (:total-input-tokens state))
      0.0
      (/ (double (:total-cost state)) (double (:total-input-tokens state)))
  )
)

